#error MUST BE INCLUDED VIA toggle.hpp or toggle.cpp!
#endif

namespace batt {
namespace detail {

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
inline i64 get_toggle_reader_id(const ToggleReaderState& state)
{
    return state.id;
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
inline i64 get_toggle_reader_id(const ToggleReaderSnapshot& snapshot)
{
    return snapshot.id;
}

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
struct OrderByToggleReaderId {
    template <typename L, typename R>
    bool operator()(const L& l, const R& r) const noexcept
    {
        return get_toggle_reader_id(l) < get_toggle_reader_id(r);
    }
};

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL ToggleReaderBase<kRecursive>::ToggleReaderBase() noexcept
    : toggle_{nullptr}
    , state_{nullptr}
    , observed_{nullptr}
{
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL ToggleReaderBase<kRecursive>::ToggleReaderBase(ToggleBase& toggle) noexcept
{
    this->activate_no_clear(toggle);
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL void ToggleReaderBase<kRecursive>::activate_impl(ToggleBase& toggle) noexcept
{
    this->clear();
    this->activate_no_clear(toggle);
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL void ToggleReaderBase<kRecursive>::activate_no_clear(ToggleBase& toggle) noexcept
{
    this->toggle_ = std::addressof(toggle);
    this->state_ = std::addressof(toggle.reader_state_slot_.get());

    const i64 old_counter = this->state_->counter.fetch_or(1);

    if constexpr (kRecursive) {
        if ((old_counter & 1) != 0) {
            this->state_->recursion_depth += 1;
        }
    } else {
        BATT_CHECK_EQ(old_counter & 1, 0) << "Only one Reader is allowed per thread at a time!";
        BATT_CHECK_EQ(this->state_->recursion_depth, 0)
            << "Reader and RecursiveReader must not be used together on the same thread!";  // LCOV_EXCL_LINE
    }

    // Now that this thread's local counter has been incremented (marking it as active), load the
    // active state.
    //
    this->observed_ = toggle.active_->load();
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL void ToggleReaderBase<kRecursive>::clear() noexcept
{
    if (this->state_) {
        if constexpr (kRecursive) {
            if (this->state_->recursion_depth == 0) {
                const i64 old_counter = this->state_->counter.fetch_add(1);
                BATT_CHECK_EQ(old_counter & 1, 1)
                    << "Recursion depth seems incorrect?"            // LCOV_EXCL_LINE
                    << BATT_INSPECT(this->state_->recursion_depth);  // LCOV_EXCL_LINE
            } else {
                this->state_->recursion_depth -= 1;
            }
        } else {
            const i64 old_counter = this->state_->counter.fetch_add(1);
            BATT_CHECK_EQ(old_counter & 1, 1) << "Only one Reader is allowed per thread at a time!";
            BATT_CHECK_EQ(this->state_->recursion_depth, 0)
                << "Reader and RecursiveReader must not be used together on the same thread!";  // LCOV_EXCL_LINE
        }

        this->state_ = nullptr;
        this->observed_ = nullptr;
    }
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL ToggleReaderBase<kRecursive>::ToggleReaderBase(Self&& other) noexcept
    : toggle_{std::exchange(other.toggle_, nullptr)}
    , state_{std::exchange(other.state_, nullptr)}
    , observed_{std::exchange(other.observed_, nullptr)}
{
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL ToggleReaderBase<kRecursive>& ToggleReaderBase<kRecursive>::operator=(Self&& other) noexcept
{
    if (this != &other) {
        this->clear();
        this->toggle_ = std::exchange(other.toggle_, nullptr);
        this->state_ = std::exchange(other.state_, nullptr);
        this->observed_ = std::exchange(other.observed_, nullptr);
    }
    return *this;
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <bool kRecursive>
BATT_INLINE_IMPL ToggleReaderBase<kRecursive>::~ToggleReaderBase() noexcept
{
    this->clear();
}

//+++++++++++-+-+--+----- --- -- -  -  -   -
// IMPORTANT: explicitly instantiate recursive and non-recursive reader templates.
//  (if we don't do this, we get linker errors in non-header-only mode)

template class ToggleReaderBase</*kRecursive=*/false>;
template class ToggleReaderBase</*kRecursive=*/true>;

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
BATT_INLINE_IMPL ToggleWriterBase::ToggleWriterBase(ToggleBase& toggle) noexcept
    : toggle_{toggle}
    , cancelled_{false}
    , observed_future_{}
    , observed_active_{}
{
    //+++++++++++-+-+--+----- --- -- -  -  -   -
    // First spin on ToggleBase::future_ until we claim exclusive access to write the future state.
    //
    for (;;) {
        this->observed_future_ = this->toggle_.future_->exchange(nullptr);
        if (this->observed_future_ != nullptr) {
            this->observed_active_ = const_cast<void*>(this->toggle_.active_->load());
            break;
        }
        batt::Task::yield();
    }
    BATT_CHECK_NE(this->observed_future_, this->observed_active_);

    //+++++++++++-+-+--+----- --- -- -  -  -   -
    // Wait for any Readers who may still be accessing the prior value.
    //
    while (!this->toggle_.waiting_for_.empty()) {
        usize n_remaining = this->toggle_.waiting_for_.size();

        // Set the `seen` flag for all readers to false so we can detect readers whose threads have gone away.
        //
        for (ToggleReaderSnapshot& snapshot : this->toggle_.waiting_for_) {
            snapshot.seen = false;
        }

        // Check all reader states to try to resolve the ones in `waiting_for`.
        //
        const bool done = this->toggle_.reader_state_slot_.visit_each(  //
            [this, &n_remaining](const ToggleReaderState& reader_state) {
                // Binary search for this reader.
                //
                auto iter = std::lower_bound(this->toggle_.waiting_for_.begin(),  //
                                             this->toggle_.waiting_for_.end(),    //
                                             reader_state, OrderByToggleReaderId{});

                // If this reader isn't in the waiting_for list, continue.
                //
                if (iter == this->toggle_.waiting_for_.end() || iter->id != reader_state.id) {
                    return false;
                }

                // Mark this one as seen so we don't remove it for the next round.
                //
                iter->seen = true;

                // If the counter is unchanged, then continue.
                //
                if (reader_state.counter.load() == iter->counter) {
                    return false;
                }

                // Since we only inserted odd reader counts into `waiting_for`, this will make it
                // even.  We will do another pass on the waiting_for list to remove this below.
                //
                ++iter->counter;

                --n_remaining;
                return n_remaining == 0;
            });

        // If we resolved all readers, then clear `waiting_for_` and return!
        //
        if (done) {
            this->toggle_.waiting_for_.clear();
            break;
        }

        // Remove all the readers whose state changed (including any who disappeared from the list).
        //
        this->toggle_.waiting_for_.erase(
            std::remove_if(this->toggle_.waiting_for_.begin(), this->toggle_.waiting_for_.end(),
                           [](const ToggleReaderSnapshot& snapshot) {
                               return /* resolved? */ (snapshot.counter % 2) == 0 ||
                                      /* not seen? */ (snapshot.seen == false);
                           }),
            this->toggle_.waiting_for_.end());

        // Give readers a chance to make progress.
        //
        batt::Task::yield();
    }
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
BATT_INLINE_IMPL ToggleWriterBase::~ToggleWriterBase() noexcept
{
    BATT_CHECK(this->toggle_.waiting_for_.empty())
        << "The prior call to ToggleWriter::ToggleWriter() should "  // LCOV_EXCL_LINE
           "have cleared the waiting_for_ list!";                    // LCOV_EXCL_LINE

    // If the write was cancelled, then just restore the observed future.
    //
    if (this->cancelled_) {
        BATT_CHECK_EQ(this->toggle_.future_->exchange(this->observed_future_), nullptr)
            << "Multiple concurrent writers detected!";  // LCOV_EXCL_LINE
        return;
    }

    // Make the new value visible to readers.
    //
    this->toggle_.active_->store(this->observed_future_);

    // When we return, restore the `future_` pointer to unblock any other writers.
    //
    auto on_scope_exit = batt::finally([this] {
        BATT_CHECK_EQ(this->toggle_.future_->exchange(this->observed_active_), nullptr)
            << "Multiple concurrent writers detected!";  // LCOV_EXCL_LINE
        ;
    });

    // Collect a list of any readers we observe to be active *after* updating the current value.
    //
    this->toggle_.reader_state_slot_.visit_each([this](const ToggleReaderState& reader_state) {
        const i64 observed_count = reader_state.counter.load();
        if ((observed_count % 2) != 0) {
            this->toggle_.waiting_for_.push_back(ToggleReaderSnapshot{
                .id = get_toggle_reader_id(reader_state),
                .counter = observed_count,
                .seen = true,
            });
        }
        return false;
    });

    // The list must be maintained in sorted order to make queries fast.
    //
    std::sort(this->toggle_.waiting_for_.begin(),  //
              this->toggle_.waiting_for_.end(),    //
              OrderByToggleReaderId{});
}

}  // namespace detail
}  // namespace batt
